    mounted() {
        window.handleExceededLink = () => {
            this.saveReportRequest();
        };
        window.handleViewLineItem = (columnId, isProcessed, lineItemId, clientId, clientName, utility, workCode, divisionName) => {
            this.openLineItemDetails(columnId, isProcessed, lineItemId, clientId, clientName, utility, workCode, divisionName);
